estimateDeliveryTime(order) {
    if (!order.assignedPartnerId) return "Not assigned";

    const partner = this.onlinePartners.find(p => p.id === order.assignedPartnerId);
    if (!partner) return "Partner offline";

    const distance = this.calculateDistance(partner.location, order.location);
    const avgSpeed = 30; // km/h
    const prepTime = 15; // minutes
    const travelTime = (distance / avgSpeed) * 60;

    return `${Math.round(prepTime + travelTime)} mins`;
}

